// Gera pontos aproximados em torno da cidade.
// Latitude: +/- 0.055 ≈ 6km
// Longitude: +/- 0.065 ≈ 6km, aproximado para boa parte do Brasil
function gerarPonto(cidade, tipo) {
  const deslocamentos = {
    centro: { lat: 0, lng: 0 },
    norte: { lat: 0.055, lng: 0 },
    sul: { lat: -0.055, lng: 0 },
    leste: { lat: 0, lng: 0.065 },
    oeste: { lat: 0, lng: -0.065 },
  };

  const d = deslocamentos[tipo] || deslocamentos.centro;

  return {
    ponto: tipo,
    lat: Number((cidade.lat + d.lat).toFixed(7)),
    lng: Number((cidade.lng + d.lng).toFixed(7)),
  };
}

function pontosPorCidade(index) {
  const posicao = index + 1;

  if (posicao <= 10) return config.pontosTop10;
  if (posicao <= 20) return config.pontosTop20;

  return config.pontosResto;
}

const tarefas = [];

cidades.forEach((cidade, index) => {
  const pontos = pontosPorCidade(index);

  pontos.forEach((pontoNome) => {
    const ponto = gerarPonto(cidade, pontoNome);

    config.zooms.forEach((zoom) => {
      const termo = `${nicho} ${cidade.cidade} ${ponto.ponto}`;
      const ll = `@${ponto.lat},${ponto.lng},${zoom}`;

      tarefas.push({
        json: {
          ...input,

          nicho,
          q: termo,

          cidade: cidade.cidade,
          uf: cidade.uf,
          cidade_uf: `${cidade.cidade}/${cidade.uf}`,

          ordem_pib_sem_rj: index + 1,
          ordem_pib_original: cidade.ordem_pib_original,

          ponto_busca: ponto.ponto,
          latitude: ponto.lat,
          longitude: ponto.lng,

          zoom,
          ll,
          geolocation: ll,

          dedupe_key_busca: [
            termo,
            cidade.cidade,
            cidade.uf,
            ponto.ponto,
            zoom,
          ].join('|'),

          serpapi_params: {
            engine: 'google_maps',
            type: 'search',
            google_domain: 'google.com.br',
            q: termo,
            ll,
            hl: 'pt',
            gl: 'br',
          },
        },
      });
    });
  });
});

return tarefas;
